function c(t){const o=typeof t=="string"?new Date(t):t,s=Math.floor((Date.now()-o.getTime())/1e3);if(s<60)return"ahora";const n=Math.floor(s/60);if(n<60)return`hace ${n} min`;const r=Math.floor(n/60);if(r<24)return`hace ${r} h`;const a=Math.floor(r/24);if(a<30)return`hace ${a} d`;const e=Math.floor(a/30);if(e<12)return`hace ${e} mes${e>1?"es":""}`;const i=Math.floor(e/12);return`hace ${i} año${i>1?"s":""}`}function f(t){return(typeof t=="string"?new Date(t):t).toLocaleDateString("es-ES",{day:"numeric",month:"long",year:"numeric"})}function u(t){return(typeof t=="string"?new Date(t):t).toLocaleString("es-ES",{day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"})}function h(t){return t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,"").slice(0,60)}export{f as a,u as f,h as s,c as t};
